// 假定获取输入的query对象
let inputQuery = $input.all()[0].json.query;

// 从输入对象中读取开始和结束日期
let activeDate_Start = inputQuery.ActiveDate_Start;
let activeDate_End = inputQuery.ActiveDate_End;

// 将字符串日期转换为Date对象
let startDate = new Date(activeDate_Start);
let endDate = new Date(activeDate_End);

// 将每月的时间段存储到categories和timeIntervals中
let categories = [];
let timeIntervals = [];

while (startDate < endDate) {
  // 当前处理的月份的年月
  let year = startDate.getFullYear();
  let month = (startDate.getMonth() + 1).toString().padStart(2, '0'); // 格式化月为两位数

  // 计算本月的结束日期
  let endOfMonth = new Date(year, startDate.getMonth() + 1, 0);

  // 如果本月结束日期超过了endDate，则使用endDate
  if (endOfMonth > endDate) {
    endOfMonth = endDate;
  }

  // 添加到categories的显示月份,包含年份
  let category = `${year}年${month}月`;
  categories.push(category);

  // 创建时间段,格式[开始时间, 结束时间]
  timeIntervals.push([
    startDate.toISOString().split('T')[0], // 当前月份的开始日期
    endOfMonth.toISOString().split('T')[0] // 当前月份的结束日期
  ]);

  // 更新下一个区间的开始日期
  startDate = new Date(year, startDate.getMonth() + 1, 1);
}

// 获取国家列表
let countries = JSON.parse(inputQuery.Country);

// 存储最终的查询参数列表
let queryList = [];

// 定义国家映射
const countryMapping = {
  "Overseas": ["US", "EU"]
};

// 对每个国家生成一个查询参数对象
for (let country of countries) {
  let mappedCountries = countryMapping[country] || [country]; // 如果为 "Overseas"，则转化为 ["US", "EU"]

  for (let mappedCountry of mappedCountries) {
    let query = {
      ...inputQuery, // 原查询参数
      "categories": categories,
      "timeIntervals": timeIntervals,
      "Country": mappedCountry
    };
    queryList.push(query);
  }
}

// 输出结果
return queryList;

const countries = $('划分时间区间').all().map(item => item.json.Country);
const timeIntervals = $('划分时间区间').all()[0].json.timeIntervals;
const categories = $('划分时间区间').all()[0].json.categories;
const List = countries.flatMap((country, countryIndex) => {
  return timeIntervals.map((interval, intervalIndex) => {
    return {
      Country: country,
      ActiveDate_End: $('划分时间区间').all()[countryIndex].json.ActiveDate_End,
      ActiveDate_Start: $('划分时间区间').all()[countryIndex].json.ActiveDate_Start,
      categories: [categories[intervalIndex]],
      timeIntervals: [interval]
    };
  });
});

return List;

// 获取唯一的categories值
const categoriesSet = new Set($input.all().map(item => item.json.categories[0]));
const categoriesData = Array.from(categoriesSet).sort();

// 构建包含国家和对应数据的对象
const countryMap = new Map();
$input.all().forEach(item => {
  const country = item.json.Country;
  const category = item.json.categories[0];
  const defectiveCount = parseInt(item.json.defectivecount);

  if (!countryMap.has(country)) {
    countryMap.set(country, {});
  }

  if (!countryMap.get(country)[category]) {
    countryMap.get(country)[category] = { defectivecount: 0, activecount: 0 };
  }

  countryMap.get(country)[category].defectivecount = defectiveCount;
});

// 将 activecount 数据加入到countryMap中
$('整理查询结果').all().forEach(item => {
  const country = item.json.Country;
  const category = item.json.categories[0];
  const activeCount = parseInt(item.json.activecount);

  if (!countryMap.has(country)) {
    countryMap.set(country, {});
  }

  if (!countryMap.get(country)[category]) {
    countryMap.get(country)[category] = { defectivecount: 0, activecount: 0 };
  }

  countryMap.get(country)[category].activecount = activeCount;
});

// 将US和EU合并为Overseas
const overseasData = {};
const combineCountries = ['US', 'EU'];

combineCountries.forEach(country => {
  const categories = countryMap.get(country);
  if (categories) {
    Object.keys(categories).forEach(category => {
      if (!overseasData[category]) {
        overseasData[category] = { defectivecount: 0, activecount: 0 };
      }
      overseasData[category].defectivecount += categories[category].defectivecount;
      overseasData[category].activecount += categories[category].activecount;
    });
    countryMap.delete(country); // 移除原始US和EU数据
  }
});

countryMap.set('Overseas', overseasData);

// 生成最终的数据结构
const result = [];
countryMap.forEach((categories, country) => {
  const defectiveCounts = categoriesData.map(category => categories[category]?.defectivecount || 0);
  const activeCounts = categoriesData.map(category => categories[category]?.activecount || 0);

  result.push({ 
    name: country, 
    defectivecounts: defectiveCounts, 
    activecounts: activeCounts 
  });
});

return {
  result: result,
  categoriesData: categoriesData // 保留categoriesData作为可能有用的引用
};

